'use client'
import { useState, useEffect, useRef, useCallback } from 'react'
import { createClient } from '@supabase/supabase-js'

const SB = process.env.NEXT_PUBLIC_SUPABASE_URL || 'https://dxipobqngyfpqbbznojz.supabase.co'
const SK = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImR4aXBvYnFuZ3lmcHFiYnpub2p6Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzI4NjcxMzgsImV4cCI6MjA4ODQ0MzEzOH0.l-6_9kOkH1mXCGvNM0WzC8naEACGMCFaneEA7XxIhKc'
const sb = createClient(SB, SK)
const SITE = typeof window!=='undefined'?window.location.origin:'https://alfanumrik-eight.vercel.app'
const aC=typeof window!=='undefined'?new(window.AudioContext||(window as any).webkitAudioContext)():null
function snd(t:string){if(!aC)return;try{aC.resume()}catch{};const o=aC.createOscillator(),g=aC.createGain();o.connect(g);g.connect(aC.destination);const n=aC.currentTime;g.gain.setValueAtTime(.12,n);if(t==='send'){o.frequency.setValueAtTime(880,n);o.frequency.linearRampToValueAtTime(1100,n+.08);g.gain.linearRampToValueAtTime(0,n+.1)}else if(t==='recv'){o.frequency.setValueAtTime(523,n);o.frequency.linearRampToValueAtTime(784,n+.2);g.gain.linearRampToValueAtTime(0,n+.25)}else if(t==='click'){o.frequency.setValueAtTime(600,n);g.gain.linearRampToValueAtTime(0,n+.05)}else if(t==='ok'){o.frequency.setValueAtTime(523,n);o.frequency.setValueAtTime(784,n+.15);g.gain.linearRampToValueAtTime(0,n+.3)}else if(t==='err'){o.frequency.setValueAtTime(300,n);o.frequency.linearRampToValueAtTime(200,n+.15);g.gain.linearRampToValueAtTime(0,n+.2)}else if(t==='correct'){o.frequency.setValueAtTime(660,n);o.frequency.setValueAtTime(880,n+.1);g.gain.setValueAtTime(.15,n);g.gain.linearRampToValueAtTime(0,n+.2)}else if(t==='wrong'){o.frequency.setValueAtTime(200,n);o.type='sawtooth';g.gain.setValueAtTime(.08,n);g.gain.linearRampToValueAtTime(0,n+.2)}else if(t==='nav'){o.frequency.setValueAtTime(700,n);g.gain.setValueAtTime(.06,n);g.gain.linearRampToValueAtTime(0,n+.04)}else if(t==='badge'){o.frequency.setValueAtTime(523,n);o.frequency.setValueAtTime(659,n+.08);o.frequency.setValueAtTime(784,n+.16);o.frequency.setValueAtTime(1047,n+.24);g.gain.linearRampToValueAtTime(0,n+.4)};o.start(n);o.stop(n+.5)}
type Screen='loading'|'auth'|'confirm'|'reset'|'onboard'|'home'|'foxy'|'quiz'|'progress'|'profile'
type Prof={name:string;grade:string;subject:string;language:string;studentId?:string}
type Stats={xp:number;streak:number;sessions:number;correct:number;asked:number;minutes:number}
const GRADES=['Grade 6','Grade 7','Grade 8','Grade 9','Grade 10','Grade 11','Grade 12']
const SUBJ=[{id:'Mathematics',icon:'\u2211',c:'#E8590C'},{id:'Science',icon:'\u269B',c:'#0C8599'},{id:'English',icon:'Aa',c:'#7C3AED'},{id:'Hindi',icon:'\u0905',c:'#D97706'},{id:'Social Studies',icon:'\uD83C\uDF0D',c:'#059669'},{id:'Physics',icon:'\u26A1',c:'#2563EB'},{id:'Chemistry',icon:'\uD83E\uDDEA',c:'#DC2626'},{id:'Biology',icon:'\uD83E\uDDEC',c:'#16A34A'},{id:'Computer Science',icon:'\uD83D\uDCBB',c:'#0D9488'},{id:'Accountancy',icon:'\uD83D\uDCCA',c:'#7C3AED'},{id:'Economics',icon:'\uD83D\uDCC8',c:'#D97706'}]
const LANGS=[{code:'en',label:'English'},{code:'hi',label:'Hindi'},{code:'ta',label:'Tamil'},{code:'te',label:'Telugu'},{code:'bn',label:'Bengali'},{code:'mr',label:'Marathi'}]
// API
async function foxyChat(msgs:any[],p:Prof){const fmt=typeof msgs==='string'?[{role:'user',content:msgs}]:Array.isArray(msgs)?msgs:[{role:'user',content:String(msgs)}];try{const r=await fetch(`${SB}/functions/v1/foxy-tutor`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({messages:fmt,student_name:p.name,grade:p.grade,subject:p.subject,language:p.language,student_id:p.studentId||null})});return await r.json()}catch{return{text:'Connection issue.'}}}
async function fetchQuiz(g:string,s:string,c:number,sid?:string,ch?:number,tp?:string){try{const r=await fetch(`${SB}/functions/v1/quiz-engine`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({subject:s,grade:g,count:c,student_id:sid||null,chapter_number:ch||undefined,topic:tp||undefined})});return await r.json()}catch{return{questions:[],chapters:[]}}}
async function submitQuiz(sid:string|null,stid:string,resp:any[],tt:number){try{const r=await fetch(`${SB}/functions/v1/quiz-submit`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({session_id:sid,student_id:stid,responses:resp,total_time_seconds:tt})});return await r.json()}catch{return{error:'Submit failed'}}}
async function speakText(t:string,l:string='en'):Promise<void>{try{const c=t.replace(/<svg[\s\S]*?<\/svg>/gi,'').substring(0,500);const r=await fetch(`${SB}/functions/v1/tts-voice`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({text:c,language:l,speed:'fast'})});const d=await r.json();if(d.audio_url)new Audio(d.audio_url).play()}catch{}}
async function ensureStudent(uid:string,p:Prof):Promise<string|null>{try{const{data:ex}=await sb.from('students').select('id').eq('auth_user_id',uid).maybeSingle();if(ex){await sb.from('students').update({name:p.name,grade:p.grade,preferred_language:p.language,onboarding_completed:true}).eq('id',ex.id);return ex.id};const{data:cr}=await sb.from('students').insert({auth_user_id:uid,name:p.name,grade:p.grade,preferred_language:p.language,onboarding_completed:true}).select('id').single();return cr?.id||null}catch(e){console.error(e);return null}}
async function getStats(sid:string):Promise<Stats>{const z:Stats={xp:0,streak:0,sessions:0,correct:0,asked:0,minutes:0};if(!sid)return z;try{const{data}=await sb.from('student_overall_stats').select('total_xp,streak_days,total_sessions,total_questions_asked,total_questions_answered_correctly,total_time_minutes').eq('student_id',sid).maybeSingle();if(!data)return z;return{xp:data.total_xp||0,streak:data.streak_days||0,sessions:data.total_sessions||0,correct:data.total_questions_answered_correctly||0,asked:data.total_questions_asked||0,minutes:data.total_time_minutes||0}}catch{return z}}
async function getDailyTopics(grade:string,subject:string){try{const m:Record<string,string>={Mathematics:'math',Science:'science',English:'english',Hindi:'hindi','Social Studies':'social_studies',Physics:'physics',Chemistry:'chemistry',Biology:'biology','Computer Science':'computer_science'};const g=parseInt(grade?.replace(/\D/g,'')||'6');let code=m[subject]||'math';if(['Physics','Chemistry','Biology'].includes(subject)&&g<11)code='science';const{data:s}=await sb.from('subjects').select('id').eq('code',code).single();if(!s)return null;const{data}=await sb.from('curriculum_topics').select('title,chapter_number,difficulty_level,estimated_minutes,description').eq('subject_id',s.id).eq('grade',grade).eq('is_active',true).order('chapter_number').order('display_order').limit(5);return data}catch{return null}}
async function getTopicMastery(sid:string,sub:string){try{const{data}=await sb.from('topic_mastery').select('topic_tag,mastery_percent,mastery_level,next_review_at,total_attempts,correct_attempts').eq('student_id',sid).eq('subject',sub).order('mastery_percent',{ascending:false}).limit(20);return data||[]}catch{return[]}}
// AUTH
function Auth({onAuth,onConfirm}:{onAuth:(u:any)=>void;onConfirm:()=>void}){const[mode,setMode]=useState<'login'|'signup'|'forgot'>('login');const[email,setEmail]=useState('');const[pw,setPw]=useState('');const[nm,setNm]=useState('');const[ld,setLd]=useState(false);const[err,setErr]=useState('');const[msg,setMsg]=useState('');const ggl=async()=>{const{error}=await sb.auth.signInWithOAuth({provider:'google',options:{redirectTo:SITE}});if(error)setErr(error.message)};const go=async()=>{setErr('');setMsg('');setLd(true);try{if(mode==='forgot'){if(!email.includes('@'))throw new Error('Valid email required');const{error}=await sb.auth.resetPasswordForEmail(email,{redirectTo:`${SITE}?reset=true`});if(error)throw error;setMsg('Reset link sent to your email!');setLd(false);return}if(!email.includes('@'))throw new Error('Valid email required');if(pw.length<6)throw new Error('6+ chars');if(mode==='signup'){if(!nm.trim())throw new Error('Name required');const{data,error}=await sb.auth.signUp({email,password:pw,options:{data:{full_name:nm},emailRedirectTo:SITE}});if(error)throw error;if(!data.session){snd('ok');onConfirm();setLd(false);return}snd('ok');onAuth(data.user)}else{const{data,error}=await sb.auth.signInWithPassword({email,password:pw});if(error)throw error;snd('ok');onAuth(data.user)}}catch(e:any){snd('err');setErr(e.message?.includes('Invalid')?'Wrong email or password':e.message||'Error')};setLd(false)};return(<div className="a-auth"><div className="a-auth-l"><div style={{fontSize:56}}>&#x1F98A;</div><h1>Alfanumrik</h1><p className="a-auth-sub">AI-powered adaptive learning for every Indian student</p><div className="a-auth-feats">{['Personalized AI tutor \u2014 Foxy','NCERT Class 6\u201312 all subjects','Learn in Hindi, English & more','AI quizzes with spaced repetition'].map(f=><div key={f} className="a-auth-feat"><span style={{color:'#E8590C',fontWeight:700}}>\u2713</span>{f}</div>)}</div></div><div className="a-auth-r"><div className="a-auth-box"><h2>{mode==='forgot'?'Reset password':mode==='signup'?'Create account':'Welcome back'}</h2><p className="a-auth-hint">{mode==='forgot'?"We'll send a reset link":mode==='signup'?'Start your journey':'Log in to continue'}</p>{mode!=='forgot'&&<div className="a-tabs">{(['login','signup']as const).map(m=><button key={m} onClick={()=>{setMode(m);setErr('');setMsg('');snd('click')}} className={`a-tab${mode===m?' on':''}`}>{m==='login'?'Log In':'Sign Up'}</button>)}</div>}{err&&<div className="a-err">{err}</div>}{msg&&<div style={{background:'#DCFCE7',color:'#15803D',border:'1px solid #BBF7D0',borderRadius:12,padding:'10px 14px',fontSize:13,marginBottom:14}}>{msg}</div>}{mode==='signup'&&<input value={nm} onChange={e=>setNm(e.target.value)} placeholder="Full name" className="a-inp"/>}<input type="email" value={email} onChange={e=>setEmail(e.target.value)} placeholder="Email" className="a-inp"/>{mode!=='forgot'&&<input type="password" value={pw} onChange={e=>setPw(e.target.value)} placeholder="Password" className="a-inp" onKeyDown={e=>e.key==='Enter'&&go()}/>}<button onClick={go} disabled={ld} className="a-btn">{ld?'Please wait...':{login:'Log In',signup:'Create Account',forgot:'Send Reset Link'}[mode]}</button>{mode==='login'&&<button onClick={()=>{setMode('forgot');setErr('');setMsg('')}} style={{width:'100%',marginTop:8,padding:10,background:'none',border:'none',color:'#E8590C',fontSize:13,fontWeight:600,cursor:'pointer',fontFamily:'inherit'}}>Forgot password?</button>}{mode==='forgot'&&<button onClick={()=>{setMode('login');setErr('');setMsg('')}} style={{width:'100%',marginTop:8,padding:10,background:'none',border:'none',color:'#78766F',fontSize:13,cursor:'pointer',fontFamily:'inherit'}}>Back to login</button>}{mode!=='forgot'&&<><div style={{display:'flex',alignItems:'center',gap:12,margin:'16px 0'}}><div style={{flex:1,height:1,background:'#E7E5E4'}}/><span style={{fontSize:12,color:'#A8A29E'}}>or</span><div style={{flex:1,height:1,background:'#E7E5E4'}}/></div><button onClick={ggl} style={{width:'100%',padding:12,borderRadius:12,border:'1px solid #E7E5E4',background:'#fff',fontSize:14,fontWeight:600,cursor:'pointer',fontFamily:'inherit',display:'flex',alignItems:'center',justifyContent:'center',gap:8,color:'#1C1917'}}><svg width="18" height="18" viewBox="0 0 48 48"><path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/><path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/><path fill="#FBBC05" d="M10.53 28.59A14.5 14.5 0 019.5 24c0-1.59.28-3.14.77-4.59l-7.98-6.19A23.9 23.9 0 000 24c0 3.87.93 7.52 2.56 10.78l7.97-6.19z"/><path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.15 1.45-4.92 2.3-8.16 2.3-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/></svg>Continue with Google</button></>}</div></div></div>)}
function ConfirmScreen({onBack}:{onBack:()=>void}){return(<div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'#1C1917',padding:24}}><div style={{maxWidth:440,textAlign:'center'}}><div style={{fontSize:64,marginBottom:16}}>&#x2709;&#xFE0F;</div><h2 style={{fontSize:24,fontWeight:800,color:'#fff',marginBottom:8}}>Check your email!</h2><p style={{fontSize:15,color:'rgba(255,255,255,.6)',lineHeight:1.6,marginBottom:24}}>We sent a verification link. Click it to activate your account and start learning with Foxy!</p><p style={{fontSize:13,color:'rgba(255,255,255,.35)',marginBottom:24}}>Check spam if you don't see it.</p><button onClick={onBack} className="a-btn" style={{maxWidth:200,margin:'0 auto'}}>Back to Login</button></div></div>)}
function ResetScreen(){const[pw,setPw]=useState('');const[pw2,setPw2]=useState('');const[ld,setLd]=useState(false);const[msg,setMsg]=useState('');const[err,setErr]=useState('');const go=async()=>{setErr('');if(pw.length<6){setErr('6+ chars');return}if(pw!==pw2){setErr('Passwords don\'t match');return}setLd(true);const{error}=await sb.auth.updateUser({password:pw});if(error)setErr(error.message);else{setMsg('Password updated! Redirecting...');setTimeout(()=>window.location.href=SITE,2000)}setLd(false)};return(<div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'#1C1917',padding:24}}><div style={{maxWidth:400,width:'100%'}}><div style={{textAlign:'center',marginBottom:32}}><div style={{fontSize:48}}>&#x1F510;</div><h2 style={{fontSize:22,fontWeight:800,color:'#fff',marginTop:12}}>Set new password</h2></div>{err&&<div className="a-err">{err}</div>}{msg&&<div style={{background:'#DCFCE7',color:'#15803D',borderRadius:12,padding:'10px 14px',fontSize:13,marginBottom:14}}>{msg}</div>}<input type="password" value={pw} onChange={e=>setPw(e.target.value)} placeholder="New password" className="a-inp" style={{background:'rgba(255,255,255,.06)',color:'#fff',borderColor:'rgba(255,255,255,.1)'}}/><input type="password" value={pw2} onChange={e=>setPw2(e.target.value)} placeholder="Confirm password" className="a-inp" style={{background:'rgba(255,255,255,.06)',color:'#fff',borderColor:'rgba(255,255,255,.1)'}} onKeyDown={e=>e.key==='Enter'&&go()}/><button onClick={go} disabled={ld} className="a-btn">{ld?'Updating...':'Update Password'}</button></div></div>)}
// ONBOARD
function Onboard({user,done}:{user:any;done:(p:Prof)=>void}){const[s,setS]=useState(0);const[nm,setNm]=useState(user?.user_metadata?.full_name||'');const[gr,setGr]=useState('');const[su,setSu]=useState('');const[la,setLa]=useState('en');const ok=[!!nm.trim(),!!gr,!!su,true][s];const titles=['What should Foxy call you?','Which grade?','Pick a subject','Choose language'];const nx=()=>{snd('click');setS(v=>v+1)};return(<div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'#1C1917'}}><div style={{width:'100%',maxWidth:480,padding:'40px 24px',textAlign:'center'}}><div style={{display:'flex',gap:6,justifyContent:'center',marginBottom:32}}>{[0,1,2,3].map(i=><div key={i} style={{height:8,borderRadius:4,background:i<=s?'#E8590C':'rgba(255,255,255,.15)',transition:'all .3s',width:i<=s?24:8}}/>)}</div><div style={{fontSize:56,marginBottom:16}}>&#x1F98A;</div><h2 style={{fontSize:26,fontWeight:800,color:'#fff',marginBottom:4}}>{titles[s]}</h2><p style={{fontSize:13,color:'rgba(255,255,255,.35)',marginBottom:28}}>Step {s+1} of 4</p><div key={s} style={{animation:'slideUp .25s',minHeight:160}}>{s===0&&<input value={nm} onChange={e=>setNm(e.target.value)} placeholder="Your name" autoFocus className="a-ob-inp" onKeyDown={e=>e.key==='Enter'&&nm.trim()&&nx()}/>}{s===1&&<div className="a-ob-g3">{GRADES.map(g=><button key={g} onClick={()=>{setGr(g);snd('click')}} className={`a-ob-ch${gr===g?' on':''}`}>{g}</button>)}</div>}{s===2&&<div className="a-ob-g2">{SUBJ.filter(x=>{const g=parseInt(gr.replace(/\D/g,'')||'6');if(g>=11)return['Mathematics','Physics','Chemistry','Biology','English','Computer Science','Accountancy','Economics'].includes(x.id);return['Mathematics','Science','English','Hindi','Social Studies'].includes(x.id)}).map(x=><button key={x.id} onClick={()=>{setSu(x.id);snd('click')}} className={`a-ob-ch${su===x.id?' on':''}`} style={su===x.id?{background:x.c}:{}}><span style={{fontSize:18}}>{x.icon}</span>{x.id}</button>)}</div>}{s===3&&<div className="a-ob-g2">{LANGS.map(l=><button key={l.code} onClick={()=>{setLa(l.code);snd('click')}} className={`a-ob-ch${la===l.code?' on':''}`}>{l.label}</button>)}</div>}</div><div style={{display:'flex',gap:10,marginTop:28}}>{s>0&&<button onClick={()=>{setS(v=>v-1);snd('click')}} className="a-ob-back">Back</button>}<button onClick={s<3?nx:()=>{snd('ok');done({name:nm.trim(),grade:gr,subject:su,language:la})}} disabled={!ok} className="a-ob-next">{s<3?'Continue':"Let's Go!"}</button></div></div></div>)}
// HOME
function Home({p,nav,stats,dt}:{p:Prof;nav:(s:Screen)=>void;stats:Stats;dt:any[]|null}){const h=new Date().getHours();const gr=h<12?'Good morning':h<17?'Good afternoon':'Good evening';const topics=dt?.slice(0,3).map((t:any,i:number)=>({t:t.title,k:['Learn','Practice','Challenge'][i],i:['\uD83D\uDCD0','\uD83C\uDFAF','\uD83E\uDDE9'][i],m:t.estimated_minutes||15,c:['#E8590C','#7C3AED','#0C8599'][i]}))||[{t:'Start learning',k:'Learn',i:'\uD83D\uDCD0',m:15,c:'#E8590C'},{t:'Quick Quiz',k:'Practice',i:'\uD83C\uDFAF',m:10,c:'#7C3AED'},{t:'Challenge',k:'Challenge',i:'\uD83E\uDDE9',m:10,c:'#0C8599'}];return(<div className="a-page"><div className="a-hdr"><div><p className="a-greet">{gr}</p><h1 className="a-title">{p.name}</h1></div><div className="a-badge">{p.grade} &middot; {p.subject}</div></div><div className="a-home-grid"><div className="a-daily"><span className="a-daily-tag">TODAY&apos;S TRAINING</span>{topics.map((t:any,i:number)=>(<button key={i} onClick={()=>{snd('click');nav(i===1?'quiz':'foxy')}} className="a-daily-row"><div className="a-daily-ic" style={{background:`${t.c}20`}}>{t.i}</div><div style={{flex:1,textAlign:'left'}}><p style={{fontSize:14,fontWeight:700,color:'#fff'}}>{t.t}</p><p style={{fontSize:12,color:'rgba(255,255,255,.4)'}}>{t.k} &middot; {t.m} min</p></div><span style={{color:'rgba(255,255,255,.25)',fontSize:20}}>&rsaquo;</span></button>))}<button onClick={()=>{snd('ok');nav('foxy')}} className="a-daily-go">Start Training</button></div><div className="a-home-r"><div className="a-qgrid">{[{i:'\uD83E\uDD8A',l:'Ask Foxy',s:'AI tutor',sc:'foxy' as Screen,c:'#E8590C'},{i:'\uD83C\uDFAF',l:'Custom Quiz',s:'Pick chapter & count',sc:'quiz' as Screen,c:'#7C3AED'},{i:'\uD83D\uDCCA',l:'Progress',s:'Real scores',sc:'progress' as Screen,c:'#0C8599'},{i:'\uD83C\uDFC6',l:'Profile',s:'Settings',sc:'profile' as Screen,c:'#D97706'}].map(a=>(<button key={a.l} onClick={()=>{snd('click');nav(a.sc)}} className="a-qcard"><div className="a-qcard-ic" style={{background:`${a.c}10`}}>{a.i}</div><p className="a-qcard-l">{a.l}</p><p className="a-qcard-s">{a.s}</p></button>))}</div><div className="a-stats">{[{v:String(stats.xp),l:'XP',i:'\u26A1'},{v:String(stats.streak),l:'Streak',i:'\uD83D\uDD25'},{v:String(stats.sessions),l:'Quizzes',i:'\u2705'}].map(x=>(<div key={x.l} className="a-stat"><span style={{fontSize:20}}>{x.i}</span><p className="a-stat-v">{x.v}</p><p className="a-stat-l">{x.l}</p></div>))}</div></div></div></div>)}
// FOXY CHAT
function Foxy({p}:{p:Prof}){const[msgs,setMsgs]=useState([{id:1,text:`Hey ${p.name}! I'm Foxy, your ${p.subject} tutor for ${p.grade}. Ask me anything \u2014 I can draw diagrams too!`,isUser:false,tag:''}]);const[inp,setInp]=useState('');const[ld,setLd]=useState(false);const[hist,setHist]=useState<any[]>([]);const[spk,setSpk]=useState<number|null>(null);const end=useRef<HTMLDivElement>(null);const iR=useRef<HTMLInputElement>(null);useEffect(()=>{end.current?.scrollIntoView({behavior:'smooth'})},[msgs]);const speak=async(id:number,t:string)=>{if(spk===id){setSpk(null);return}setSpk(id);await speakText(t,p.language);setSpk(null)};const renderMsg=(t:string)=>{if(!t.includes('<svg'))return t;const parts=t.split(/(<svg[\s\S]*?<\/svg>)/gi);return <>{parts.map((pt,i)=>pt.startsWith('<svg')?<div key={i} style={{margin:'8px 0',maxWidth:400}} dangerouslySetInnerHTML={{__html:pt}}/>:<span key={i}>{pt}</span>)}</>};const send=async(t:string)=>{if(!t.trim()||ld)return;const m=t.trim();snd('send');setMsgs(v=>[...v,{id:Date.now(),text:m,isUser:true,tag:''}]);setInp('');setLd(true);const nh=[...hist,{role:'user',content:m}];const res=await foxyChat(nh,p);snd('recv');let tag='';if(res.analysis?.strength){tag='\u2B50 '+res.analysis.strength;snd('badge')}if(res.analysis?.weakness){tag='\u26A0\uFE0F '+res.analysis.weakness};setMsgs(v=>[...v,{id:Date.now()+1,text:res.text||'Foxy had a hiccup!',isUser:false,tag}]);setHist([...nh,{role:'assistant',content:res.text}]);setLd(false);iR.current?.focus()};return(<div className="a-chat"><div className="a-chat-hdr"><div className="a-chat-av">&#x1F98A;</div><div><p style={{fontSize:15,fontWeight:700,color:'#1C1917'}}>Foxy &mdash; MIGA Tutor</p><p style={{fontSize:12,color:'#A8A29E'}}>{p.subject} &middot; {p.grade} &middot; Voice + Diagrams</p></div></div><div className="a-chat-body">{msgs.map(m=>(<div key={m.id} className={`a-msg ${m.isUser?'u':'b'}`}>{!m.isUser&&<div className="a-msg-av">&#x1F98A;</div>}<div><div className={`a-bub ${m.isUser?'u':'b'}`}>{m.isUser?m.text:renderMsg(m.text)}</div><div style={{display:'flex',gap:6,marginTop:4}}>{!m.isUser&&<button onClick={()=>speak(m.id,m.text)} className="a-speak-btn">{spk===m.id?'\uD83D\uDD0A':'\uD83D\uDD08'}</button>}{m.tag&&<div className="a-insight">{m.tag}</div>}</div></div></div>))}{ld&&<div className="a-msg b"><div className="a-msg-av">&#x1F98A;</div><div className="a-typing"><span/><span/><span/></div></div>}<div ref={end}/></div>{msgs.length<=2&&<div className="a-chips">{['Explain a concept','Draw a number line','Give me a question','Help with homework','Quiz me'].map(c=><button key={c} onClick={()=>send(c)} className="a-chip">{c}</button>)}</div>}<div className="a-chat-bar"><input ref={iR} value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={e=>e.key==='Enter'&&send(inp)} placeholder="Ask Foxy anything... (try 'draw a triangle')" className="a-chat-inp"/><button onClick={()=>send(inp)} disabled={!inp.trim()||ld} className="a-chat-go"><svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M7 12V4m0 0L3 8m4-4l4 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/></svg></button></div></div>)}
// QUIZ with custom chapter/count selector
function Quiz({p,onDone}:{p:Prof;onDone:()=>void}){const[phase,setPhase]=useState<'setup'|'play'|'done'>('setup');const[qs,setQs]=useState<any[]>([]);const[ci,setCi]=useState(0);const[sel,setSel]=useState<number|null>(null);const[score,setScore]=useState(0);const[rev,setRev]=useState(false);const[sesId,setSesId]=useState<string|null>(null);const[resps,setResps]=useState<any[]>([]);const[result,setResult]=useState<any>(null);const[qStart,setQStart]=useState(Date.now());const[qzStart,setQzStart]=useState(Date.now());const[ld,setLd]=useState(false);const[chs,setChs]=useState<any[]>([]);const[selCh,setSelCh]=useState<number|null>(null);const[selN,setSelN]=useState(10);
useEffect(()=>{(async()=>{const d=await fetchQuiz(p.grade,p.subject,0,p.studentId);setChs(d.chapters||[])})()},[p.grade,p.subject,p.studentId]);
const start=async()=>{setLd(true);const d=await fetchQuiz(p.grade,p.subject,selN,p.studentId,selCh||undefined);setQs(d.questions||[]);setSesId(d.session_id||null);setLd(false);if(d.questions?.length){setPhase('play');setQStart(Date.now());setQzStart(Date.now())}};
const pick=(i:number)=>{if(rev)return;setSel(i);setRev(true);const q=qs[ci];const ok=i===q.correct_answer_index;if(ok){setScore(s=>s+1);snd('correct')}else snd('wrong');setResps(v=>[...v,{question_number:ci+1,question_text:q.question_text,question_type:'mcq',options:q.options,correct_answer_index:q.correct_answer_index,correct_answer_text:q.options?.[q.correct_answer_index]||'',student_answer_index:i,student_answer_text:q.options?.[i]||'',is_correct:ok,time_taken_seconds:Math.round((Date.now()-qStart)/1000),marks:q.marks||1,explanation:q.explanation||'',topic_tag:q.topic_tag||'general',bloom_level:q.bloom_level||'understand',difficulty:q.difficulty||2,subject:p.subject,grade:p.grade,chapter_number:q.chapter_number||1}])};
const next=async()=>{if(ci<qs.length-1){setCi(v=>v+1);setSel(null);setRev(false);snd('click');setQStart(Date.now())}else{setPhase('done');snd('badge');if(p.studentId){const r=await submitQuiz(sesId,p.studentId,resps,Math.round((Date.now()-qzStart)/1000));setResult(r);if(r.success)onDone()}}};
const reset=()=>{setPhase('setup');setCi(0);setSel(null);setRev(false);setScore(0);setResps([]);setResult(null);setQs([])};
if(phase==='setup')return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Custom Quiz</h1><p className="a-greet">{p.subject} &middot; {p.grade}</p></div></div><div className="a-card" style={{maxWidth:600}}><h3 className="a-card-t">CONFIGURE YOUR QUIZ</h3><label style={{fontSize:13,fontWeight:700,color:'#57534E',display:'block',marginBottom:6}}>Chapter (optional)</label><div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:16}}><button onClick={()=>setSelCh(null)} style={{padding:'6px 12px',borderRadius:8,border:selCh===null?'2px solid #E8590C':'1px solid #E7E5E4',background:selCh===null?'#FFF7ED':'#fff',color:selCh===null?'#E8590C':'#57534E',fontSize:12,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>All chapters</button>{chs.map(c=><button key={c.chapter} onClick={()=>{setSelCh(c.chapter);snd('click')}} style={{padding:'6px 12px',borderRadius:8,border:selCh===c.chapter?'2px solid #E8590C':'1px solid #E7E5E4',background:selCh===c.chapter?'#FFF7ED':'#fff',color:selCh===c.chapter?'#E8590C':'#57534E',fontSize:11,fontWeight:600,cursor:'pointer',fontFamily:'inherit'}}>Ch{c.chapter}: {c.title?.substring(0,22)}</button>)}</div><label style={{fontSize:13,fontWeight:700,color:'#57534E',display:'block',marginBottom:6}}>Questions</label><div style={{display:'flex',gap:8,marginBottom:16}}>{[5,10,15,20,25].map(n=><button key={n} onClick={()=>{setSelN(n);snd('click')}} style={{padding:'8px 16px',borderRadius:10,border:selN===n?'2px solid #E8590C':'1px solid #E7E5E4',background:selN===n?'#E8590C':'#fff',color:selN===n?'#fff':'#57534E',fontSize:14,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>{n}</button>)}</div><button onClick={start} disabled={ld} className="a-daily-go">{ld?'Generating...':selCh?`Start \u2014 ${selN} Qs from Ch${selCh}`:`Start \u2014 ${selN} mixed Qs`}</button></div></div>);
if(phase==='done'){const pct=qs.length?Math.round((score/qs.length)*100):0;const xp=result?.xp_earned||0;return<div className="a-page" style={{textAlign:'center',paddingTop:40}}><div style={{fontSize:64,marginBottom:12}}>{pct>=80?'\uD83C\uDF89':pct>=50?'\uD83D\uDC4D':'\uD83D\uDCAA'}</div><h2 style={{fontSize:28,fontWeight:900}}>Quiz Complete!</h2><p style={{fontSize:16,color:'#A8A29E',margin:'8px 0 20px'}}>{score}/{qs.length} correct ({pct}%)</p><div style={{display:'flex',gap:12,justifyContent:'center',marginBottom:20,flexWrap:'wrap'}}><div className="a-stat" style={{minWidth:70}}><p className="a-stat-v" style={{color:'#16A34A'}}>{score}</p><p className="a-stat-l">Correct</p></div><div className="a-stat" style={{minWidth:70}}><p className="a-stat-v" style={{color:'#DC2626'}}>{qs.length-score}</p><p className="a-stat-l">Wrong</p></div><div className="a-stat" style={{minWidth:70}}><p className="a-stat-v" style={{color:'#E8590C'}}>{pct}%</p><p className="a-stat-l">Score</p></div>{xp>0&&<div className="a-stat" style={{minWidth:70}}><p className="a-stat-v" style={{color:'#D97706'}}>+{xp}</p><p className="a-stat-l">XP</p></div>}</div>{result?.topic_mastery?.length>0&&<div className="a-card" style={{maxWidth:400,margin:'0 auto 20px',textAlign:'left'}}><h3 className="a-card-t">TOPIC MASTERY</h3>{result.topic_mastery.map((t:any,i:number)=><div key={i} style={{marginBottom:10}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}><span style={{fontSize:13,fontWeight:600}}>{t.topic?.replace(/_/g,' ')}</span><span style={{fontSize:12,fontWeight:700,color:t.mastery>=70?'#16A34A':t.mastery>=40?'#D97706':'#DC2626'}}>{t.mastery}% {t.level}</span></div><div style={{height:6,borderRadius:3,background:'#F5F4F0'}}><div style={{height:'100%',borderRadius:3,width:`${t.mastery}%`,background:t.mastery>=70?'#16A34A':t.mastery>=40?'#D97706':'#DC2626'}}/></div></div>)}</div>}{result?.message&&<p style={{fontSize:14,color:'#57534E',marginBottom:20}}>{result.message}</p>}<button onClick={reset} className="a-daily-go" style={{maxWidth:300,margin:'0 auto',display:'block'}}>Take Another Quiz</button></div>}
const q=qs[ci];if(!q)return<div className="a-page" style={{textAlign:'center',paddingTop:80}}><p style={{fontSize:48}}>&#x1F614;</p><p style={{fontWeight:700,marginTop:12}}>No questions</p><button onClick={reset} className="a-daily-go" style={{maxWidth:200,margin:'20px auto'}}>Back</button></div>;
return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Quiz</h1><p className="a-greet">{p.subject}{q.topic_tag?' \u2022 '+q.topic_tag.replace(/_/g,' '):''}</p></div><div className="a-badge">Q{ci+1}/{qs.length} &middot; {score} correct</div></div><div className="a-card" style={{maxWidth:700}}><div style={{display:'flex',gap:3,marginBottom:16}}>{qs.map((_:any,i:number)=><div key={i} style={{flex:1,height:4,borderRadius:2,background:i<ci?(resps[i]?.is_correct?'#16A34A':'#DC2626'):i===ci?'#E8590C':'#EDEBE6'}}/>)}</div><p style={{fontSize:12,color:'#A8A29E',marginBottom:4}}>Q{ci+1}/{qs.length} &middot; {q.difficulty<=1?'Easy':q.difficulty<=2?'Medium':'Hard'}</p><h3 style={{fontSize:17,fontWeight:700,marginBottom:18,lineHeight:1.5}}>{q.question_text}</h3><div style={{display:'flex',flexDirection:'column',gap:8}}>{(q.options as string[]).map((opt:string,idx:number)=>{const isC=idx===q.correct_answer_index;const isS=idx===sel;let bg='#fff',bd='1px solid #E7E5E4',cl='#1C1917';if(rev&&isC){bg='#DCFCE7';bd='1.5px solid #16A34A';cl='#15803D'}else if(rev&&isS&&!isC){bg='#FEE2E2';bd='1.5px solid #DC2626';cl='#B91C1C'}else if(isS){bg='#FFF7ED';bd='1.5px solid #E8590C';cl='#E8590C'};return<button key={idx} onClick={()=>pick(idx)} style={{padding:'12px 14px',borderRadius:12,background:bg,border:bd,color:cl,fontSize:14,fontWeight:600,textAlign:'left',cursor:rev?'default':'pointer',fontFamily:'inherit',transition:'all .15s'}}>{String.fromCharCode(65+idx)}. {opt}</button>})}</div>{rev&&<div style={{marginTop:14,padding:12,borderRadius:12,background:'#F5F4F0'}}><p style={{fontSize:13,fontWeight:700,color:sel===q.correct_answer_index?'#16A34A':'#DC2626',marginBottom:4}}>{sel===q.correct_answer_index?'Correct! \uD83C\uDF89':'Not quite \uD83D\uDCA1'}</p>{q.explanation&&<p style={{fontSize:13,color:'#57534E',lineHeight:1.5}}>{q.explanation}</p>}</div>}{rev&&<button onClick={next} className="a-daily-go" style={{marginTop:14}}>{ci<qs.length-1?'Next':'Finish & See Results'}</button>}</div></div>)}
// PROGRESS
function Progress({p,stats}:{p:Prof;stats:Stats}){const[mastery,setMastery]=useState<any[]>([]);useEffect(()=>{if(p.studentId){const m:Record<string,string>={Mathematics:'math',Science:'science',English:'english',Hindi:'hindi','Social Studies':'social_studies',Physics:'physics',Chemistry:'chemistry',Biology:'biology'};getTopicMastery(p.studentId,m[p.subject]||'math').then(setMastery)}},[p.studentId,p.subject]);const acc=stats.asked>0?Math.round((stats.correct/stats.asked)*100):0;return(<div className="a-page"><div className="a-hdr"><div><h1 className="a-title">Progress</h1><p className="a-greet">{p.subject} &middot; {p.grade}</p></div></div><div className="a-stats" style={{marginBottom:20,gridTemplateColumns:'repeat(3,1fr)'}}>{[{v:String(stats.xp),l:'Total XP',i:'\u26A1'},{v:String(stats.streak),l:'Streak',i:'\uD83D\uDD25'},{v:String(stats.sessions),l:'Quizzes',i:'\uD83D\uDCDA'},{v:`${acc}%`,l:'Accuracy',i:'\uD83C\uDFAF'},{v:String(stats.minutes),l:'Minutes',i:'\u23F1\uFE0F'},{v:String(stats.asked),l:'Questions',i:'\u2753'}].map(x=>(<div key={x.l} className="a-stat"><span style={{fontSize:18}}>{x.i}</span><p className="a-stat-v">{x.v}</p><p className="a-stat-l">{x.l}</p></div>))}</div>{mastery.length>0&&<div className="a-card"><h3 className="a-card-t">SKILL MASTERY</h3>{mastery.map((t:any,i:number)=><div key={i} style={{marginBottom:12}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}><span style={{fontSize:13,fontWeight:600}}>{t.topic_tag?.replace(/_/g,' ')}</span><span style={{fontSize:12,fontWeight:700,color:t.mastery_percent>=70?'#16A34A':t.mastery_percent>=40?'#D97706':'#DC2626'}}>{t.mastery_percent}% {t.mastery_level}</span></div><div style={{height:6,borderRadius:3,background:'#F5F4F0'}}><div style={{height:'100%',borderRadius:3,width:`${t.mastery_percent}%`,background:t.mastery_percent>=70?'#16A34A':t.mastery_percent>=40?'#D97706':'#DC2626'}}/></div><p style={{fontSize:10,color:'#A8A29E',marginTop:2}}>{t.total_attempts} attempts &middot; {t.correct_attempts} correct</p></div>)}</div>}{!mastery.length&&<div className="a-card" style={{textAlign:'center',padding:40}}><p style={{fontSize:40}}>&#x1F4CA;</p><p style={{fontWeight:700,marginTop:8}}>No mastery data yet</p><p style={{color:'#A8A29E',fontSize:13,marginTop:4}}>Complete a quiz to see topic-by-topic progress!</p></div>}</div>)}
// PROFILE
function ProfileScr({p,onUp,out,stats}:{p:Prof;onUp:(p:Prof)=>void;out:()=>void;stats:Stats}){const[ed,setEd]=useState<string|null>(null);const[nm,setNm]=useState(p.name);const[gr,setGr]=useState(p.grade);const[su,setSu]=useState(p.subject);const[la,setLa]=useState(p.language);const save=()=>{snd('ok');onUp({...p,name:nm,grade:gr,subject:su,language:la});setEd(null)};const acc=stats.asked>0?Math.round((stats.correct/stats.asked)*100):0;return(<div className="a-page"><div style={{textAlign:'center',padding:'16px 0 20px'}}><div style={{width:72,height:72,borderRadius:'50%',margin:'0 auto 10px',background:'linear-gradient(135deg,#E8590C,#DC2626)',color:'#fff',display:'flex',alignItems:'center',justifyContent:'center',fontSize:28,fontWeight:900}}>{nm.charAt(0).toUpperCase()}</div><h1 style={{fontSize:22,fontWeight:900}}>{nm}</h1><p style={{fontSize:13,color:'#A8A29E',marginTop:4}}>{gr} &middot; {su} &middot; {LANGS.find(l=>l.code===la)?.label}</p><div style={{display:'flex',justifyContent:'center',gap:20,marginTop:12}}>{[{v:String(stats.xp),l:'XP'},{v:String(stats.sessions),l:'Quizzes'},{v:`${acc}%`,l:'Accuracy'}].map(x=>(<div key={x.l}><p style={{fontSize:18,fontWeight:900}}>{x.v}</p><p style={{fontSize:10,color:'#A8A29E',fontWeight:600}}>{x.l}</p></div>))}</div></div><div style={{maxWidth:520,margin:'0 auto'}}>{[{k:'name',l:'Name',v:nm},{k:'grade',l:'Grade',v:gr},{k:'subject',l:'Subject',v:su},{k:'lang',l:'Language',v:LANGS.find(l=>l.code===la)?.label}].map(f=><div key={f.k} className="a-card" style={{padding:0,overflow:'hidden',marginBottom:10}}><div className="a-pr" onClick={()=>{setEd(ed===f.k?null:f.k);snd('click')}}><span className="a-pr-l">{f.l}</span><span className="a-pr-v">{ed===f.k?'':f.v}</span><span style={{color:'#A8A29E'}}>{ed===f.k?'\u2715':'\u270E'}</span></div>{ed===f.k&&<div className="a-ed">{f.k==='name'&&<><input value={nm} onChange={e=>setNm(e.target.value)} className="a-ed-inp" autoFocus/><button onClick={save} disabled={!nm.trim()} className="a-ed-btn">Save</button></>}{f.k==='grade'&&<><div style={{display:'flex',gap:6,flexWrap:'wrap'}}>{GRADES.map(g=><button key={g} onClick={()=>{setGr(g);snd('click')}} style={{padding:'7px 11px',borderRadius:10,border:gr===g?'none':'1px solid #E7E5E4',background:gr===g?'#E8590C':'#fff',color:gr===g?'#fff':'#1C1917',fontSize:12,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>{g}</button>)}</div><button onClick={save} className="a-ed-btn" style={{marginTop:8}}>Save</button></>}{f.k==='subject'&&<><div style={{display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:6}}>{SUBJ.filter(x=>{const g=parseInt(gr.replace(/\D/g,'')||'6');if(g>=11)return['Mathematics','Physics','Chemistry','Biology','English','Computer Science','Accountancy','Economics'].includes(x.id);return['Mathematics','Science','English','Hindi','Social Studies'].includes(x.id)}).map(x=><button key={x.id} onClick={()=>{setSu(x.id);snd('click')}} style={{padding:'7px 9px',borderRadius:10,border:su===x.id?'none':'1px solid #E7E5E4',background:su===x.id?x.c:'#fff',color:su===x.id?'#fff':'#1C1917',fontSize:11,fontWeight:700,cursor:'pointer',fontFamily:'inherit',display:'flex',alignItems:'center',gap:5}}><span>{x.icon}</span>{x.id}</button>)}</div><button onClick={save} className="a-ed-btn" style={{marginTop:8}}>Save</button></>}{f.k==='lang'&&<><div style={{display:'flex',gap:6,flexWrap:'wrap'}}>{LANGS.map(l=><button key={l.code} onClick={()=>{setLa(l.code);snd('click')}} style={{padding:'7px 11px',borderRadius:10,border:la===l.code?'none':'1px solid #E7E5E4',background:la===l.code?'#E8590C':'#fff',color:la===l.code?'#fff':'#1C1917',fontSize:12,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>{l.label}</button>)}</div><button onClick={save} className="a-ed-btn" style={{marginTop:8}}>Save</button></>}</div>}</div>)}<button onClick={()=>{snd('click');out()}} style={{width:'100%',marginTop:8,padding:12,borderRadius:14,border:'none',background:'#FEE2E2',color:'#DC2626',fontSize:13,fontWeight:700,cursor:'pointer',fontFamily:'inherit'}}>Sign Out</button><p style={{textAlign:'center',fontSize:10,color:'#D4D0C8',marginTop:20}}>Alfanumrik v3.0 &middot; Cusiosense Learning India Pvt. Ltd.</p></div></div>)}
// NAV
function Nav({active,nav,p}:{active:Screen;nav:(s:Screen)=>void;p:Prof}){const tabs=[{sc:'home' as Screen,l:'Today',i:'\u2299'},{sc:'foxy' as Screen,l:'Foxy',i:'\uD83E\uDD8A'},{sc:'quiz' as Screen,l:'Quiz',i:'\uD83C\uDFAF'},{sc:'progress' as Screen,l:'Progress',i:'\u25D4'},{sc:'profile' as Screen,l:'Profile',i:'\u25D0'}];return(<><nav className="a-side"><div className="a-side-brand"><span style={{fontSize:24}}>&#x1F98A;</span><span className="a-side-name">Alfanumrik</span></div><div className="a-side-nav">{tabs.map(t=><button key={t.sc} onClick={()=>{snd('nav');nav(t.sc)}} className={`a-side-btn${active===t.sc?' on':''}`}><span className="a-side-ic">{t.i}</span><span>{t.l}</span></button>)}</div><div className="a-side-user"><div className="a-side-av">{p.name.charAt(0)}</div><div><p style={{fontSize:13,fontWeight:700}}>{p.name}</p><p style={{fontSize:11,color:'#A8A29E'}}>{p.grade}</p></div></div></nav><nav className="a-bot">{tabs.map(t=><button key={t.sc} onClick={()=>{snd('nav');nav(t.sc)}} className={`a-bot-btn${active===t.sc?' on':''}`}><span className="a-bot-ic">{t.i}</span><span className="a-bot-lb">{t.l}</span></button>)}</nav></>)}
// MAIN
export default function App(){
  const[sc,setSc]=useState<Screen>('loading');const[user,setUser]=useState<any>(null);const[prof,setProf]=useState<Prof|null>(null);const[stats,setStats]=useState<Stats>({xp:0,streak:0,sessions:0,correct:0,asked:0,minutes:0});const[dt,setDt]=useState<any[]|null>(null)
  const load=useCallback(async(p:Prof)=>{if(!p.studentId)return;const s=await getStats(p.studentId);setStats(s);const t=await getDailyTopics(p.grade,p.subject);if(t)setDt(t)},[])
  useEffect(()=>{if(typeof window!=='undefined'){const params=new URLSearchParams(window.location.search);if(params.get('reset')==='true'||window.location.hash.includes('type=recovery')){setSc('reset');return}}
  sb.auth.getSession().then(async({data:{session}})=>{if(session?.user){setUser(session.user);const saved=localStorage.getItem('alfanumrik_profile');if(saved){const p=JSON.parse(saved)as Prof;const sid=await ensureStudent(session.user.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);localStorage.setItem('alfanumrik_profile',JSON.stringify(wp));await load(wp);setSc('home')}else setSc('onboard')}else setSc('auth')});
  const{data:{subscription}}=sb.auth.onAuthStateChange(async(ev,s)=>{if(s?.user){setUser(s.user);const saved=localStorage.getItem('alfanumrik_profile');if(saved){const p=JSON.parse(saved)as Prof;const sid=await ensureStudent(s.user.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);await load(wp);setSc('home')}else setSc('onboard')}else if(sc!=='reset'&&sc!=='confirm'){setUser(null);setSc('auth')}});return()=>subscription.unsubscribe()},[load])
  const onAuth=async(u:any)=>{setUser(u);const saved=localStorage.getItem('alfanumrik_profile');if(saved){const p=JSON.parse(saved)as Prof;const sid=await ensureStudent(u.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);localStorage.setItem('alfanumrik_profile',JSON.stringify(wp));await load(wp);setSc('home')}else setSc('onboard')}
  const onOb=async(p:Prof)=>{if(user){const sid=await ensureStudent(user.id,p);const wp={...p,studentId:sid||undefined};setProf(wp);localStorage.setItem('alfanumrik_profile',JSON.stringify(wp));const t=await getDailyTopics(p.grade,p.subject);if(t)setDt(t);setSc('home')}}
  const onProfUp=async(p:Prof)=>{setProf(p);localStorage.setItem('alfanumrik_profile',JSON.stringify(p));if(p.studentId){await sb.from('students').update({name:p.name,grade:p.grade,preferred_language:p.language}).eq('id',p.studentId);await load(p)};const t=await getDailyTopics(p.grade,p.subject);if(t)setDt(t)}
  const refreshStats=async()=>{if(prof?.studentId){const s=await getStats(prof.studentId);setStats(s)}}
  const logout=async()=>{await sb.auth.signOut();localStorage.removeItem('alfanumrik_profile');setUser(null);setProf(null);setSc('auth')}
  if(sc==='loading')return<><CSS/><div style={{minHeight:'100vh',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:12}}><div style={{fontSize:48,animation:'pulse 1.5s infinite'}}>&#x1F98A;</div><p style={{fontSize:14,color:'#A8A29E',fontWeight:600}}>Loading...</p></div></>
  if(sc==='auth')return<><CSS/><Auth onAuth={onAuth} onConfirm={()=>setSc('confirm')}/></>
  if(sc==='confirm')return<><CSS/><ConfirmScreen onBack={()=>setSc('auth')}/></>
  if(sc==='reset')return<><CSS/><ResetScreen/></>
  if(sc==='onboard')return<><CSS/><Onboard user={user} done={onOb}/></>
  return(<><CSS/><div className="a-shell">{prof&&<Nav active={sc} nav={setSc} p={prof}/>}<main className="a-main">{sc==='home'&&prof&&<Home p={prof} nav={setSc} stats={stats} dt={dt}/>}{sc==='foxy'&&prof&&<Foxy p={prof}/>}{sc==='quiz'&&prof&&<Quiz p={prof} onDone={refreshStats}/>}{sc==='progress'&&prof&&<Progress p={prof} stats={stats}/>}{sc==='profile'&&prof&&<ProfileScr p={prof} onUp={onProfUp} out={logout} stats={stats}/>}</main></div></>)}

function CSS(){return<style>{`
@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800;900&display=swap');
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}body{font-family:'DM Sans',sans-serif;background:#FAFAF8;color:#1C1917;-webkit-font-smoothing:antialiased;overflow-x:hidden}::selection{background:#E8590C;color:#fff}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-thumb{background:#E7E5E4;border-radius:3px}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}@keyframes slideUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}
.a-auth{min-height:100vh;display:flex}.a-auth-l{flex:1;background:linear-gradient(135deg,#1C1917,#292524);padding:60px;display:flex;flex-direction:column;justify-content:center;color:#fff}.a-auth-l h1{font-size:42px;font-weight:900;letter-spacing:-.02em;margin-top:16px}.a-auth-sub{font-size:16px;color:rgba(255,255,255,.5);margin-top:8px}.a-auth-feats{display:flex;flex-direction:column;gap:12px;margin-top:48px}.a-auth-feat{font-size:15px;color:rgba(255,255,255,.7);display:flex;align-items:center;gap:10px}.a-auth-r{flex:1;display:flex;align-items:center;justify-content:center;padding:40px}.a-auth-box{width:100%;max-width:400px}.a-auth-box h2{font-size:28px;font-weight:800;margin-bottom:4px}.a-auth-hint{font-size:14px;color:#A8A29E;margin-bottom:24px}
.a-tabs{display:flex;gap:4px;background:#F3F2EE;border-radius:12px;padding:4px;margin-bottom:20px}.a-tab{flex:1;padding:10px;border-radius:10px;border:none;font-size:13px;font-weight:700;cursor:pointer;background:transparent;color:#A8A29E;font-family:inherit;transition:all .2s}.a-tab.on{background:#fff;color:#1C1917;box-shadow:0 1px 3px rgba(0,0,0,.08)}
.a-err{background:#FEE2E2;color:#B91C1C;border:1px solid #FECACA;border-radius:12px;padding:10px 14px;font-size:13px;margin-bottom:14px}.a-inp{width:100%;padding:14px 16px;border-radius:12px;border:1.5px solid #E7E5E4;background:#FAFAF8;font-size:14px;outline:none;margin-bottom:12px;font-family:inherit;color:#1C1917;transition:border-color .2s}.a-inp:focus{border-color:#E8590C}.a-btn{width:100%;padding:14px;border-radius:12px;border:none;background:#E8590C;color:#fff;font-size:15px;font-weight:700;cursor:pointer;font-family:inherit;margin-top:4px}.a-btn:disabled{opacity:.5}
.a-ob-inp{width:100%;padding:16px;border-radius:16px;border:1.5px solid rgba(255,255,255,.1);background:rgba(255,255,255,.06);color:#fff;font-size:18px;font-weight:700;text-align:center;outline:none;font-family:inherit}.a-ob-g3{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.a-ob-g2{display:grid;grid-template-columns:repeat(2,1fr);gap:8px}.a-ob-ch{padding:14px 12px;border-radius:14px;border:1px solid rgba(255,255,255,.08);background:rgba(255,255,255,.05);color:rgba(255,255,255,.7);font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;text-align:left;display:flex;align-items:center;gap:8px;transition:all .15s}.a-ob-ch.on{background:#E8590C;color:#fff;border-color:transparent}.a-ob-back{flex:1;padding:14px;border-radius:14px;border:none;background:rgba(255,255,255,.08);color:rgba(255,255,255,.6);font-size:14px;font-weight:700;cursor:pointer;font-family:inherit}.a-ob-next{flex:2;padding:14px;border-radius:14px;border:none;background:#E8590C;color:#fff;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit}.a-ob-next:disabled{opacity:.3}
.a-shell{display:flex;min-height:100vh}.a-main{flex:1;margin-left:240px;min-height:100vh;overflow-y:auto}
.a-side{width:240px;background:#fff;border-right:1px solid #E7E5E4;display:flex;flex-direction:column;position:fixed;top:0;left:0;bottom:0;z-index:50}.a-side-brand{padding:24px 20px;display:flex;align-items:center;gap:10px;border-bottom:1px solid #F3F2EE}.a-side-name{font-size:17px;font-weight:800}.a-side-nav{flex:1;padding:12px 10px;display:flex;flex-direction:column;gap:2px}.a-side-btn{display:flex;align-items:center;gap:12px;padding:12px 14px;border-radius:12px;border:none;background:transparent;cursor:pointer;font-family:inherit;font-size:14px;font-weight:600;color:#78766F;transition:all .15s;width:100%;text-align:left}.a-side-btn:hover{background:#F5F4F0;color:#1C1917}.a-side-btn.on{background:rgba(232,89,12,.08);color:#E8590C}.a-side-ic{font-size:18px;width:24px;text-align:center}.a-side-user{padding:16px 14px;border-top:1px solid #F3F2EE;display:flex;align-items:center;gap:10px}.a-side-av{width:32px;height:32px;border-radius:10px;background:linear-gradient(135deg,#E8590C,#DC2626);color:#fff;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:800;flex-shrink:0}
.a-bot{display:none;position:fixed;bottom:0;left:0;right:0;background:rgba(255,255,255,.97);backdrop-filter:blur(20px);border-top:1px solid #E7E5E4;padding:6px 0 env(safe-area-inset-bottom,10px);z-index:50;justify-content:space-around}.a-bot-btn{display:flex;flex-direction:column;align-items:center;gap:2px;padding:6px 12px;border:none;background:none;cursor:pointer;font-family:inherit}.a-bot-ic{font-size:18px;opacity:.35;transition:opacity .2s}.a-bot-btn.on .a-bot-ic{opacity:1}.a-bot-lb{font-size:10px;font-weight:700;color:#A8A29E}.a-bot-btn.on .a-bot-lb{color:#E8590C}
.a-page{padding:32px 40px;max-width:1200px;animation:fadeIn .3s}.a-hdr{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:28px}.a-greet{font-size:14px;font-weight:500;color:#A8A29E}.a-title{font-size:28px;font-weight:900;margin-top:2px}.a-badge{padding:6px 14px;border-radius:10px;background:#F5F4F0;font-size:13px;font-weight:600;color:#57534E}
.a-home-grid{display:grid;grid-template-columns:380px 1fr;gap:24px;align-items:start}.a-home-r{display:flex;flex-direction:column;gap:20px}.a-daily{background:linear-gradient(135deg,#1C1917,#292524);border-radius:20px;padding:24px}.a-daily-tag{font-size:10px;font-weight:800;padding:4px 10px;border-radius:6px;background:rgba(232,89,12,.2);color:#E8590C;letter-spacing:.05em}.a-daily-row{width:100%;display:flex;align-items:center;gap:12px;padding:12px;border-radius:14px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.05);margin-top:8px;cursor:pointer;font-family:inherit;transition:background .15s}.a-daily-row:hover{background:rgba(255,255,255,.1)}.a-daily-ic{width:40px;height:40px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0}.a-daily-go{width:100%;margin-top:12px;padding:14px;border-radius:14px;border:none;background:#E8590C;color:#fff;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit}.a-daily-go:hover{opacity:.9}.a-daily-go:disabled{opacity:.4}
.a-qgrid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.a-qcard{padding:20px;border-radius:16px;background:#fff;border:1px solid #E7E5E4;text-align:left;cursor:pointer;font-family:inherit;transition:all .15s}.a-qcard:hover{border-color:#ccc;transform:translateY(-2px);box-shadow:0 4px 12px rgba(0,0,0,.04)}.a-qcard-ic{width:40px;height:40px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:18px;margin-bottom:10px}.a-qcard-l{font-size:14px;font-weight:700}.a-qcard-s{font-size:12px;color:#A8A29E;margin-top:2px}
.a-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.a-stat{padding:14px;border-radius:16px;background:#F5F4F0;text-align:center}.a-stat-v{font-size:20px;font-weight:900;margin:4px 0 0}.a-stat-l{font-size:10px;color:#A8A29E;font-weight:600}
.a-card{background:#fff;border:1px solid #E7E5E4;border-radius:16px;padding:24px;margin-bottom:16px}.a-card-t{font-size:11px;font-weight:800;letter-spacing:.08em;color:#A8A29E;margin-bottom:16px}
.a-chat{display:flex;flex-direction:column;height:100vh;animation:fadeIn .3s}.a-chat-hdr{padding:16px 24px;display:flex;align-items:center;gap:12px;border-bottom:1px solid #E7E5E4;background:#fff}.a-chat-av{width:36px;height:36px;border-radius:12px;background:linear-gradient(135deg,#E8590C,#DC2626);display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0}.a-chat-body{flex:1;overflow-y:auto;padding:24px;display:flex;flex-direction:column;gap:12px}
.a-msg{display:flex;max-width:720px}.a-msg.u{justify-content:flex-end;align-self:flex-end;margin-left:auto}.a-msg.b{justify-content:flex-start}.a-msg-av{width:28px;height:28px;border-radius:10px;background:linear-gradient(135deg,#E8590C,#DC2626);display:flex;align-items:center;justify-content:center;font-size:14px;margin-right:8px;margin-top:4px;flex-shrink:0}
.a-bub{padding:12px 16px;border-radius:16px;font-size:14px;line-height:1.6;white-space:pre-wrap;max-width:600px}.a-bub.u{background:#1C1917;color:#fff;border-top-right-radius:4px}.a-bub.b{background:#fff;color:#1C1917;border:1px solid #E7E5E4;border-top-left-radius:4px}
.a-typing{display:flex;gap:4px;padding:8px 12px}.a-typing span{width:6px;height:6px;border-radius:50%;background:#E8590C;animation:pulse 1s infinite}.a-typing span:nth-child(2){animation-delay:.2s}.a-typing span:nth-child(3){animation-delay:.4s}
.a-chips{padding:0 24px 12px;display:flex;gap:8px;flex-wrap:wrap}.a-chip{padding:8px 14px;border-radius:20px;background:#F5F4F0;border:1px solid #E7E5E4;font-size:13px;font-weight:600;color:#57534E;cursor:pointer;font-family:inherit}.a-chip:hover{background:#E7E5E4}
.a-insight{padding:4px 10px;border-radius:8px;font-size:11px;font-weight:700;background:#FFF7ED;color:#C2410C;border:1px solid #FDBA74;display:inline-block}
.a-speak-btn{padding:3px 8px;border-radius:8px;border:1px solid #E7E5E4;background:#fff;font-size:14px;cursor:pointer;line-height:1}.a-speak-btn:hover{background:#FFF7ED;border-color:#FDBA74}
.a-chat-bar{padding:12px 24px 24px;display:flex;gap:8px;align-items:center;background:#fff;border-top:1px solid #F5F4F0}.a-chat-inp{flex:1;padding:14px 16px;border-radius:14px;border:1.5px solid #E7E5E4;background:#FAFAF8;font-size:14px;outline:none;font-family:inherit;color:#1C1917}.a-chat-inp:focus{border-color:#E8590C}.a-chat-go{width:44px;height:44px;border-radius:12px;border:none;display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;background:#F5F4F0;color:#A8A29E}.a-chat-go:not(:disabled){background:#E8590C;color:#fff}
.a-pr{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;cursor:pointer}.a-pr:hover{background:#FAFAF8}.a-pr-l{font-size:14px;font-weight:600}.a-pr-v{font-size:14px;color:#78766F;flex:1;text-align:right;margin-right:8px}.a-ed{padding:12px 20px 16px;border-top:1px solid #F5F4F0;background:#FAFAF8}.a-ed-inp{width:100%;padding:10px 14px;border-radius:10px;border:1.5px solid #E7E5E4;font-size:14px;outline:none;font-family:inherit;color:#1C1917;margin-bottom:8px}.a-ed-inp:focus{border-color:#E8590C}.a-ed-btn{padding:8px 20px;border-radius:10px;border:none;background:#E8590C;color:#fff;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit}
@media(max-width:900px){.a-side{display:none}.a-main{margin-left:0}.a-bot{display:flex}.a-page{padding:20px 16px 100px}.a-home-grid{grid-template-columns:1fr}.a-title{font-size:22px}.a-auth{flex-direction:column}.a-auth-l{padding:40px 24px;min-height:auto}.a-auth-l h1{font-size:28px!important}.a-auth-r{padding:24px}.a-chat{height:calc(100vh - 70px)}.a-chat-bar{padding:12px 16px 20px}}
`}</style>}
